import torch.nn.functional as F

# r_chosen, r_rejected: scalar reward for each response in a pair
def reward_loss(r_chosen, r_rejected):
    # Bradley-Terry: chosen should outscore rejected
    return -F.logsigmoid(r_chosen - r_rejected).mean()

# lower loss  ->  bigger margin between good and bad answers

from datasets import load_dataset

# DPOTrainer expects three columns: prompt, chosen, rejected
ds = load_dataset("Anthropic/hh-rlhf", split="train[:2000]")

def to_pref(ex):
    # hh-rlhf stores full transcripts; split off the final answer
    prompt = ex["chosen"].rsplit("Assistant:", 1)[0] + "Assistant:"
    return {"prompt": prompt,
            "chosen":   ex["chosen"][len(prompt):],
            "rejected": ex["rejected"][len(prompt):]}

ds = ds.map(to_pref)
